import{c as t,Q as o,j as s,m as a}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I switch between customers?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/switch-customer.md","filePath":"guide/recipes/portal/switch-customer.md","lastUpdated":1779094756000}'),r={name:"guide/recipes/portal/switch-customer.md"};function i(c,e,n,l,h,u){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="how-do-i-switch-between-customers" tabindex="-1">How do I switch between customers? <a class="header-anchor" href="#how-do-i-switch-between-customers" aria-label="Permalink to &quot;How do I switch between customers?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p>Anyone who belongs to <strong>more than one customer</strong></p></div><p>If you&#39;ve been invited to multiple customers — for example as a contractor working with several Exto clients — a switcher appears in the portal header.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open the portal. Look at the header — top left, next to the customer name.</li><li>Click the dropdown arrow next to the current customer name.</li><li>Pick the customer you want to switch to.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The portal reloads scoped to the new customer. Your sidebar, dashboard, tenants, users, and billing all reflect that customer&#39;s data only. The customer switcher remains in the header so you can jump back any time.</p><div class="tip custom-block"><p class="custom-block-title">Only one customer?</p><p>If you belong to a single customer, the switcher is hidden — you just see the customer name in the header.</p></div>',8)])])}const m=t(r,[["render",i]]);export{p as __pageData,m as default};
